import React, { useState } from 'react';
import StatCard from '../components/StatCard';

const Customers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [activeTab, setActiveTab] = useState('all');

    const customers = [
        { id: 1, name: 'Rahul Kumar', email: 'rahul@email.com', phone: '+91 9876543210', totalBookings: 8, totalSpent: 36000, lastBooking: '2026-02-24', status: 'active' },
        { id: 2, name: 'Priya Sharma', email: 'priya@email.com', phone: '+91 9876543211', totalBookings: 5, totalSpent: 22500, lastBooking: '2026-02-23', status: 'active' },
        { id: 3, name: 'Amit Patel', email: 'amit@email.com', phone: '+91 9876543212', totalBookings: 12, totalSpent: 54000, lastBooking: '2026-02-23', status: 'active' },
        { id: 4, name: 'Sneha Reddy', email: 'sneha@email.com', phone: '+91 9876543213', totalBookings: 3, totalSpent: 11400, lastBooking: '2026-02-22', status: 'active' },
        { id: 5, name: 'Vikram Singh', email: 'vikram@email.com', phone: '+91 9876543214', totalBookings: 6, totalSpent: 28800, lastBooking: '2026-02-22', status: 'active' },
        { id: 6, name: 'Neha Gupta', email: 'neha@email.com', phone: '+91 9876543215', totalBookings: 4, totalSpent: 25200, lastBooking: '2026-02-21', status: 'active' },
        { id: 7, name: 'Arjun Nair', email: 'arjun@email.com', phone: '+91 9876543216', totalBookings: 2, totalSpent: 10800, lastBooking: '2026-02-19', status: 'inactive' },
        { id: 8, name: 'Kavitha Menon', email: 'kavitha@email.com', phone: '+91 9876543217', totalBookings: 7, totalSpent: 31500, lastBooking: '2026-02-18', status: 'active' },
        { id: 9, name: 'Deepak Verma', email: 'deepak@email.com', phone: '+91 9876543218', totalBookings: 1, totalSpent: 1800, lastBooking: '2026-02-10', status: 'inactive' },
        { id: 10, name: 'Ananya Iyer', email: 'ananya@email.com', phone: '+91 9876543219', totalBookings: 9, totalSpent: 40500, lastBooking: '2026-02-24', status: 'active' },
    ];

    const filtered = customers.filter(c => {
        const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.email.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesTab = activeTab === 'all' || c.status === activeTab;
        return matchesSearch && matchesTab;
    });

    const totalCustomers = customers.length;
    const activeCustomers = customers.filter(c => c.status === 'active').length;
    const totalRevenue = customers.reduce((sum, c) => sum + c.totalSpent, 0);
    const avgRevenue = Math.round(totalRevenue / totalCustomers);

    const getInitials = (name) => name.split(' ').map(n => n[0]).join('').toUpperCase();
    const getAvatarColor = (id) => {
        const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#6366f1', '#ec4899', '#14b8a6', '#8b5cf6'];
        return colors[(id - 1) % colors.length];
    };

    return (
        <div>
            {/* Stats */}
            <div className="stats-grid">
                <StatCard icon="👥" label="Total Customers" value={totalCustomers} color="blue" trend="up" trendValue="3 new" />
                <StatCard icon="✅" label="Active Customers" value={activeCustomers} color="green" />
                <StatCard icon="🔄" label="Repeat Rate" value="68%" color="orange" trend="up" trendValue="5%" />
                <StatCard icon="💰" label="Avg Revenue / Customer" value={`₹${avgRevenue.toLocaleString()}`} color="purple" />
            </div>

            {/* Toolbar */}
            <div className="toolbar">
                <div className="toolbar-search">
                    <span className="toolbar-search-icon">🔍</span>
                    <input
                        type="text"
                        placeholder="Search customers..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>

                <div className="filter-tabs">
                    <button className={`filter-tab ${activeTab === 'all' ? 'active' : ''}`} onClick={() => setActiveTab('all')}>All</button>
                    <button className={`filter-tab ${activeTab === 'active' ? 'active' : ''}`} onClick={() => setActiveTab('active')}>Active</button>
                    <button className={`filter-tab ${activeTab === 'inactive' ? 'active' : ''}`} onClick={() => setActiveTab('inactive')}>Inactive</button>
                </div>

                <button className="btn btn-secondary btn-sm" style={{ marginLeft: 'auto' }}>📥 Export</button>
            </div>

            {/* Customer Table */}
            <div className="card">
                <div className="data-table-container">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Customer</th>
                                <th>Phone</th>
                                <th>Total Bookings</th>
                                <th>Total Spent</th>
                                <th>Last Booking</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filtered.map(customer => (
                                <tr key={customer.id}>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                            <div style={{
                                                width: 36, height: 36, borderRadius: '50%',
                                                background: getAvatarColor(customer.id),
                                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                                color: '#fff', fontWeight: 600, fontSize: '0.75rem', flexShrink: 0,
                                            }}>
                                                {getInitials(customer.name)}
                                            </div>
                                            <div>
                                                <div className="table-cell-main">{customer.name}</div>
                                                <div className="table-cell-sub">{customer.email}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td>{customer.phone}</td>
                                    <td className="table-cell-main">{customer.totalBookings}</td>
                                    <td className="table-cell-main">₹{customer.totalSpent.toLocaleString()}</td>
                                    <td>
                                        <div className="table-cell-sub">
                                            {new Date(customer.lastBooking).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                                        </div>
                                    </td>
                                    <td>
                                        <span className={`badge badge--${customer.status === 'active' ? 'success' : 'neutral'}`}>
                                            <span className="badge-dot"></span>
                                            {customer.status}
                                        </span>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', gap: '0.35rem' }}>
                                            <button className="btn btn-ghost btn-sm">View</button>
                                            <button className="btn btn-ghost btn-sm">Email</button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                <div className="card-footer" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                        Showing {filtered.length} of {customers.length} customers
                    </span>
                </div>
            </div>
        </div>
    );
};

export default Customers;
